    defer chunks_content.deinit(std.heap.c_allocator);
    while (true) {
        const _nc = liter_llm.c.literllm_default_client_chat_stream_next(_stream_handle);
        if (_nc == null) break;
        const _np = liter_llm.c.literllm_chat_completion_chunk_to_json(_nc);
        liter_llm.c.literllm_chat_completion_chunk_free(_nc);
        if (_np == null) continue;
        const _ns = std.mem.span(_np);
        const _nj = try std.heap.c_allocator.dupe(u8, _ns);
        liter_llm.c.literllm_free_string(_np);
        if (std.json.parseFromSlice(std.json.Value, std.heap.c_allocator, _nj, .{})) |_cp| {
            defer _cp.deinit();
            if (_cp.value.object.get("choices")) |_chs|
                if (_chs.array.items.len > 0)
                    if (_chs.array.items[0].object.get("delta")) |_dl|
                        if (_dl.object.get("content")) |_ct|
                            if (_ct == .string) try chunks_content.appendSlice(std.heap.c_allocator, _ct.string);
        } else |_| {}
        try chunks.append(std.heap.c_allocator, _nj);
    }
    try testing.expect(chunks.items.len >= 1);
}

test "vertex_chat" {
    // Basic chat completion via the Google Vertex AI provider using the vertex_ai/ prefix for routing — verifies the prefix is stripped before dispatching and the Gemini response is normalised to the standard OpenAI chat completion shape
    var gpa: std.heap.DebugAllocator(.{}) = .init;
    defer _ = gpa.deinit();
    const allocator = gpa.allocator();

    const _mock_url = try std.fmt.allocPrintSentinel(std.heap.c_allocator, "{s}/fixtures/vertex_chat", .{if (std.c.getenv("MOCK_SERVER_URL")) |v| std.mem.span(v) else "http://localhost:8080"}, 0);
    defer std.heap.c_allocator.free(_mock_url);
    var _client = try liter_llm.create_client("test-key", _mock_url, null, null, null);
    defer _client.free();
    const _result_json = try _client.chat("{\"max_tokens\":16,\"messages\":[{\"content\":\"Say hello in one word.\",\"role\":\"user\"}],\"model\":\"vertex_ai/gemini-2.0-flash\",\"temperature\":0}");
    defer std.heap.c_allocator.free(_result_json);
    var _parsed = try std.json.parseFromSlice(std.json.Value, allocator, _result_json, .{});
    defer _parsed.deinit();
    const result = &_parsed.value;
    try testing.expectEqual(1, result.object.get("choices").?.array.items.len);
    try testing.expectEqualStrings("Hello!", std.mem.trim(u8, result.object.get("choices").?.array.items[0].object.get("message").?.object.get("content").?.string, " \n\r\t"));
    try testing.expectEqualStrings("stop", std.mem.trim(u8, result.object.get("choices").?.array.items[0].object.get("finish_reason").?.string, " \n\r\t"));
    try testing.expectEqualStrings("gemini-2.0-flash", std.mem.trim(u8, result.object.get("model").?.string, " \n\r\t"));
    try testing.expectEqual(13, result.object.get("usage").?.object.get("total_tokens").?.integer);
}

